from dataclasses import dataclass
from typing import Optional

@dataclass
class EvalCase:
    question: str
    ground_truth: Optional[str]  # None = unanswerable
    expected_classification: str  # "idk" | "confident"

def run_calibration_eval(
    cases: list[EvalCase],
    answer_fn  # fn(question) -> str
) -> dict:
    results = {
        "true_idk": 0,       # said IDK on unanswerable
        "false_idk": 0,      # said IDK on answerable (too cautious)
        "true_confident": 0, # gave correct confident answer
        "hallucination": 0,  # gave confident answer on unanswerable
    }
    for case in cases:
        answer = answer_fn(case.question)
        clf = classify_answer(answer)
        is_idk = clf == "idk"
        unanswerable = case.ground_truth is None

        if unanswerable and is_idk:
            results["true_idk"] += 1
        elif unanswerable and not is_idk:
            results["hallucination"] += 1
        elif not unanswerable and is_idk:
            results["false_idk"] += 1
        else:
            results["true_confident"] += 1

    total = len(cases)
    results["hallucination_rate"] = results["hallucination"] / total
    results["idk_recall"] = results["true_idk"] / max(
        1, results["true_idk"] + results["hallucination"]
    )
    return results

from collections import defaultdict
from datetime import datetime, timedelta

class UncertaintyMonitor:
    def __init__(self, window_hours: int = 24):
        self.window = timedelta(hours=window_hours)
        self._log: list[dict] = []

    def record(self, answer: str, timestamp: datetime | None = None):
        ts = timestamp or datetime.utcnow()
        clf = classify_answer(answer)  # from earlier
        self._log.append({"ts": ts, "classification": clf})

    def recent_stats(self) -> dict:
        cutoff = datetime.utcnow() - self.window
        recent = [r for r in self._log if r["ts"] >= cutoff]
        if not recent:
            return {"total": 0}
        counts = defaultdict(int)
        for r in recent:
            counts[r["classification"]] += 1
        total = len(recent)
        return {
            "total": total,
            "idk_rate": counts["idk"] / total,
            "hedged_rate": counts["hedged"] / total,
            "confident_rate": counts["confident"] / total,
        }

    def alert_if_anomalous(
        self,
        baseline_idk_rate: float,
        threshold: float = 0.15
    ) -> str | None:
        stats = self.recent_stats()
        if stats["total"] < 50:
            return None  # not enough data
        delta = abs(stats["idk_rate"] - baseline_idk_rate)
        if delta > threshold:
            return (
                f"IDK rate anomaly: current={stats['idk_rate']:.2f}, "
                f"baseline={baseline_idk_rate:.2f}, delta={delta:.2f}"
            )
        return None
